file.content:
html {
  scroll-behavior: smooth;
}

/*
Theme Name: App Economy
Author: WordPress Telex
Description: A professional, SEO-optimized blog theme focused on earning money online through apps and legitimate methods. Clean fintech editorial design with strategic ad placement zones.
Version: 0.1.0
Requires at least: 6.4
Tested up to: 6.8
Requires PHP: 7.4
License: GPLv2 or later
Text Domain: app-economy
Tags: block-theme, full-site-editing, blog, seo-ready

App Economy — Earn smarter, live better.
*/

/* Equal cards layout */
.equal-cards > .wp-block-column {
  display: flex;
  flex-direction: column;
  flex-grow: 0;
}
.equal-cards > .wp-block-column > .wp-block-group {
  display: flex;
  flex-direction: column;
  flex-grow: 1;
}
.equal-cards .cta-bottom {
  margin-top: auto;
  justify-content: center;
}

.wp-site-blocks > footer {
  margin-block-start: 0;
}

/* App grid cards */
.app-grid-cards .wp-block-column {
  display: flex;
  flex-direction: column;
}
.app-grid-cards .wp-block-column > .wp-block-group {
  display: flex;
  flex-direction: column;
  flex-grow: 1;
  transition: transform 0.25s ease, box-shadow 0.25s ease;
}
.app-grid-cards .wp-block-column > .wp-block-group:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 30px rgba(0,0,0,0.12);
}

/* Badge styles */
.hero-badge p {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  margin: 0;
}
.hero-badge p::before {
  content: '';
  display: inline-block;
  width: 8px;
  height: 8px;
  background: #10B981;
  border-radius: 50%;
  flex-shrink: 0;
  animation: pulse-dot 2s ease-in-out infinite;
}
@keyframes pulse-dot {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.6; transform: scale(1.3); }
}

/* Highlight underline effect */
.highlight-text mark {
  background: none;
  position: relative;
  display: inline;
  color: inherit;
}
.highlight-text mark::after {
  content: '';
  position: absolute;
  bottom: 2px;
  left: -4px;
  right: -4px;
  height: 8px;
  background: #FF6B35;
  opacity: 0.35;
  border-radius: 4px;
  z-index: -1;
}

/* Trust items row */
.trust-row .wp-block-group {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}

/* Sticky header */
.site-header {
  position: sticky;
  top: 0;
  z-index: 100;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
}

/* Ad placement zones */
.ad-zone {
  text-align: center;
  min-height: 90px;
  display: flex;
  align-items: center;
  justify-content: center;
}
.ad-zone p {
  font-size: 0.7rem;
  text-transform: uppercase;
  letter-spacing: 0.1em;
  opacity: 0.4;
}

/* Grid pattern overlay */
.grid-pattern-overlay::before {
  content: '';
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(229,231,235,0.3) 1px, transparent 1px),
    linear-gradient(90deg, rgba(229,231,235,0.3) 1px, transparent 1px);
  background-size: 60px 60px;
  pointer-events: none;
  z-index: 0;
  mask-image: radial-gradient(ellipse at center, black 20%, transparent 70%);
  -webkit-mask-image: radial-gradient(ellipse at center, black 20%, transparent 70%);
}

/* Floating stat cards on hero image */
.hero-image-container {
  position: relative;
}
.floating-stat {
  position: absolute;
  z-index: 3;
  background: #FFFFFF;
  border-radius: 12px;
  box-shadow: 0 8px 24px rgba(0,0,0,0.1);
  padding: 12px 16px;
  display: flex;
  align-items: center;
  gap: 10px;
}
.floating-stat-left {
  bottom: 20px;
  left: -16px;
}
.floating-stat-right {
  top: 20px;
  right: -16px;
}
.stat-icon {
  width: 36px;
  height: 36px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
.stat-icon-green {
  background: rgba(16,185,129,0.1);
  color: #10B981;
}
.stat-icon-orange {
  background: rgba(255,107,53,0.1);
  color: #FF6B35;
}
.stat-label {
  font-size: 0.68rem;
  font-weight: 600;
  color: #374151;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}
.stat-value {
  font-size: 1rem;
  font-weight: 800;
  color: #111827;
}

@media (max-width: 768px) {
  .floating-stat-left {
    left: 8px;
    bottom: 12px;
  }
  .floating-stat-right {
    right: 8px;
    top: 12px;
  }
}
@media (max-width: 480px) {
  .floating-stat {
    display: none;
  }
}

/* Earning badge */
.earning-badge p {
  display: inline-block;
  font-size: 0.75rem;
  font-weight: 600;
  color: #10B981;
  background: rgba(16,185,129,0.08);
  padding: 3px 12px;
  border-radius: 100px;
  margin: 0;
}

/* App icon blocks */
.app-icon-block {
  width: 48px;
  height: 48px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 0 auto;
}

/* Top tag */
.top-tag {
  position: absolute;
  top: -6px;
  right: -6px;
  z-index: 2;
}
.top-tag p {
  background: #FF6B35;
  color: #FFFFFF;
  font-size: 0.6rem;
  font-weight: 800;
  padding: 3px 8px;
  border-radius: 6px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin: 0;
}

/* Step number circles */
.step-number {
  width: 48px;
  height: 48px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 800;
  font-size: 1.1rem;
  flex-shrink: 0;
}

/* Section fade-in animations */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(24px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
.animate-section {
  animation: fadeInUp 0.7s ease-out both;
}

/* Navigation link styles */
.nav-links a {
  text-decoration: none;
  font-weight: 600;
  font-size: 0.9rem;
  position: relative;
  padding-bottom: 2px;
}
.nav-links a::after {
  content: '';
  position: absolute;
  bottom: -2px;
  left: 0;
  width: 0;
  height: 2px;
  background: #FF6B35;
  border-radius: 2px;
  transition: width 0.25s ease;
}
.nav-links a:hover::after {
  width: 100%;
}

/* CTA button hover effects */
.wp-block-button.is-style-fill .wp-block-button__link {
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}
.wp-block-button.is-style-fill .wp-block-button__link:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(255,107,53,0.35);
}

/* Feature icon containers */
.feature-icon {
  width: 56px;
  height: 56px;
  border-radius: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

/* Testimonial card special */
.testimonial-card {
  position: relative;
}
.testimonial-card::before {
  content: '\201C';
  position: absolute;
  top: -8px;
  left: 20px;
  font-size: 4rem;
  color: #FF6B35;
  opacity: 0.15;
  font-family: Georgia, serif;
  line-height: 1;
}

